import React, { useState, useEffect } from 'react';
import SensorForm from './SensorForm';
import PredictionResult from './PredictionResult';
import PredictionDetail from './PredictionDetail';
import AlertPanel from './AlertPanel';
import MaintenanceReport from './MaintenanceReport';
import ReportDetail from './ReportDetail';
import { getAlerts, acknowledgeAlert, resolveAlert, generateReport, getMachines } from '../services/api';
import './Dashboard.css';

function Dashboard({ user, onLogout }) {
  const [predictionResult, setPredictionResult] = useState(null);
  const [predictionDetail, setPredictionDetail] = useState(null);
  const [alerts, setAlerts] = useState([]);
  const [machines, setMachines] = useState([]);
  const [selectedMachine, setSelectedMachine] = useState(null);
  const [report, setReport] = useState(null);
  const [loadingReport, setLoadingReport] = useState(false);
  const [tab, setTab] = useState('monitor'); // 'monitor', 'alerts', 'report'
  const [reportDetail, setReportDetail] = useState(null); // For detailed report view

  // Load machines on mount
  useEffect(() => {
    loadMachines();
    loadAlerts();
  }, []);

  const loadMachines = async () => {
    try {
      const data = await getMachines();
      // Ensure machines is always an array
      setMachines(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error('Error loading machines:', error);
      setMachines([]);
    }
  };

  const loadAlerts = async () => {
    try {
      const data = await getAlerts('OPEN');
      setAlerts(data || []);
    } catch (error) {
      console.error('Error loading alerts:', error);
      setAlerts([]);
    }
  };

  const handleSensorSubmit = (result) => {
    setPredictionResult(result);
    setPredictionDetail(result);
    loadAlerts();
  };

  const handleBackFromPrediction = () => {
    setPredictionDetail(null);
    setTab('monitor');
  };

  const handleAcknowledgeAlert = async (alertId) => {
    try {
      await acknowledgeAlert(alertId);
      loadAlerts();
    } catch (error) {
      console.error('Error acknowledging alert:', error);
    }
  };

  const handleResolveAlert = async (alertId) => {
    try {
      await resolveAlert(alertId);
      loadAlerts();
    } catch (error) {
      console.error('Error resolving alert:', error);
    }
  };

  const handleGenerateReport = async () => {
    if (!selectedMachine) {
      alert('Please select a machine');
      return;
    }

    setLoadingReport(true);
    try {
      const reportData = await generateReport(selectedMachine.id);
      setReport(reportData);
      setReportDetail(reportData); // Show detailed report page
      setTab('reportDetail');
    } catch (error) {
      console.error('Error generating report:', error);
      alert('Failed to generate report');
    } finally {
      setLoadingReport(false);
    }
  };

  const handleBackFromReport = () => {
    setReportDetail(null);
    setTab('report');
  };

  // If prediction detail is shown, display it
  if (predictionDetail) {
    return <PredictionDetail prediction={predictionDetail} onBack={handleBackFromPrediction} />;
  }

  // If detailed report is shown, display it
  if (reportDetail) {
    return <ReportDetail report={reportDetail} onBack={handleBackFromReport} />;
  }

  return (
    <div className="dashboard-container">
      {/* Header */}
      <header className="dashboard-header">
        <div className="header-left">
          <h1 className="app-title">🏭 Refinery Maintenance</h1>
          <p className="app-subtitle">Predictive Equipment Monitoring</p>
        </div>
        <div className="header-right">
          <span className="user-info">👤 {user.name || 'User'}</span>
          <button className="logout-button" onClick={onLogout}>
            Logout
          </button>
        </div>
      </header>

      {/* Tabs Navigation */}
      <nav className="dashboard-nav">
        <button
          className={`nav-tab ${tab === 'monitor' ? 'active' : ''}`}
          onClick={() => setTab('monitor')}
        >
          📊 Monitor
        </button>
        <button
          className={`nav-tab ${tab === 'alerts' ? 'active' : ''}`}
          onClick={() => setTab('alerts')}
        >
          🚨 Alerts {Array.isArray(alerts) && alerts.length > 0 && <span className="badge">{alerts.length}</span>}
        </button>
        <button
          className={`nav-tab ${tab === 'report' ? 'active' : ''}`}
          onClick={() => setTab('report')}
        >
          📈 Reports
        </button>
      </nav>

      {/* Content Area */}
      <main className="dashboard-content">
        {/* Monitor Tab */}
        {tab === 'monitor' && (
          <div className="tab-content">
            <div className="monitor-section">
              <div className="sensor-section">
                <h2>📝 Submit Sensor Reading</h2>
                <SensorForm onSubmit={handleSensorSubmit} />
              </div>

              {predictionResult && (
                <div className="result-section">
                  <h2>🔮 Prediction Result</h2>
                  <PredictionResult result={predictionResult} />
                </div>
              )}
            </div>
          </div>
        )}

        {/* Alerts Tab */}
        {tab === 'alerts' && (
          <div className="tab-content">
            <AlertPanel
              alerts={alerts}
              onAcknowledge={handleAcknowledgeAlert}
              onResolve={handleResolveAlert}
            />
          </div>
        )}

        {/* Reports Tab */}
        {tab === 'report' && (
          <div className="tab-content">
            <div className="report-section">
              <h2>📋 Generate Maintenance Report</h2>
              
              <div className="machine-selector">
                <label>Select Machine:</label>
                <select
                  value={selectedMachine?.id || ''}
                  onChange={(e) => {
                    const machine = machines.find(m => m.id === parseInt(e.target.value));
                    setSelectedMachine(machine);
                  }}
                >
                  <option value="">-- Choose a machine --</option>
                  {Array.isArray(machines) && machines.map(machine => (
                    <option key={machine.id} value={machine.id}>
                      {machine.name} ({machine.machine_id})
                    </option>
                  ))}
                </select>
              </div>

              <button
                className="generate-button"
                onClick={handleGenerateReport}
                disabled={!selectedMachine || loadingReport}
              >
                {loadingReport ? '⏳ Generating...' : '📊 Generate Report'}
              </button>

              {report && (
                <div className="report-preview">
                  <h3>Current Report Preview</h3>
                  <MaintenanceReport report={report} />
                  <button
                    className="view-full-button"
                    onClick={() => {
                      setReportDetail(report);
                      setTab('reportDetail');
                    }}
                  >
                    View Full Report →
                  </button>
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="dashboard-footer">
        <p>Refinery Predictive Maintenance System v1.0 | AI-Powered Equipment Monitoring</p>
      </footer>
    </div>
  );
}

export default Dashboard;
